// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('Check label 部署', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('Check label 部署', async function() {
    // Test name: Check label 部署
    // Step # | name | target | value
    // 1 | open | http://localhost:4200/user/evaluation-reference-pro | 
    await driver.get("http://localhost:4200/user/evaluation-reference-pro");

    // 2 | setWindowSize | 1936x1056 | 
    await driver.manage().window().setRect({ width: 1936, height: 1056 });

    // 3 | click | css=.ant-form-item-no-colon | 
    await driver.findElement(By.css(".ant-form-item-no-colon")).click();

    // 4 | click | css=.ant-form-item-no-colon | 
    await driver.findElement(By.css(".ant-form-item-no-colon")).click();

    // 5 | doubleClick | css=.ant-form-item-no-colon | 
    {
      const element = await driver.findElement(By.css(".ant-form-item-no-colon"));
      await driver.actions({ bridge: true}).doubleClick(element).perform();
    }

    // 6 | verifyText | css=.ant-form-item-no-colon | 部署
    assert(await driver.findElement(By.css(".ant-form-item-no-colon")).getText() == "部署");
  });
});
